(()=>{window.runParallel=async(n,f=4,c=4,d=1e4)=>{let h=Math.min(f,n.length),r=new Array(h).fill(null).map(()=>new Worker("/worker-parallel.js")),l=new Array(n.length),a=0,o=new Set;r.forEach((e,t)=>{e.onmessage=i=>{let{id:s,result:w,error:u}=i.data,v=Number(s);if(l[v]=w||{error:u},o.delete(t),a<n.length){let g=a++;o.add(t),e.postMessage({cmd:"solve",id:String(g),problem:n[g],maxDepth:c,timeLimitMs:d})}}});for(let e=0;e<r.length&&!(a>=n.length);e++){let t=a++;o.add(e),r[e].postMessage({cmd:"solve",id:String(t),problem:n[t],maxDepth:c,timeLimitMs:d})}return await new Promise(e=>{let t=setInterval(()=>{l.filter(s=>s!==void 0).length===n.length&&(clearInterval(t),e())},50)}),r.forEach(e=>e.terminate()),l};})();
